          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //MARK: WHERE RULES (ENTITY)
      public static func WHERE_wr1(SELF: eANNOTATION_PLACEHOLDER_OCCURRENCE.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
        //
        let _TEMP1 /* SDAI.BOOLEAN? */ = MD_VALID_CONTENT_IN_GEOMETRIC_SET_FOR_PLACEHOLDER( 
            SELF.ITEM )
        return SDAI.LOGICAL(_TEMP1)
      }
      public static func WHERE_wr2(SELF: eANNOTATION_PLACEHOLDER_OCCURRENCE.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
        //
        let _TEMP1 /* nANNOTATION_PLACEHOLDER_OCCURRENCE_ROLE?? */ = nANNOTATION_PLACEHOLDER_OCCURRENCE_ROLE.GPS_DATA
        let _TEMP2 /* SDAI.LOGICAL */ = SELF.ROLE .==. SDAI.FORCE_OPTIONAL(_TEMP1)
        let _TEMP3 /* SDAI.LOGICAL */ =  !_TEMP2
        let _TEMP4 /* SDAI.INTEGER? */ = SDAI.SIZEOF( SELF.THE_DRAUGHTING_MODEL_ITEM_ASSOCIATION_WITH_PLACEHOLDERS )
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP4 .==. SDAI.FORCE_OPTIONAL(SDAI.INTEGER(1))
        let _TEMP6 /* SDAI.BOOLEAN? */ = MD_PMI_NAME_AND_TYPE_CORRELATION( 
            SELF )
        let _TEMP7 /* SDAI.LOGICAL */ = _TEMP5 && _TEMP6
        let _TEMP8 /* SDAI.LOGICAL */ = _TEMP3 || _TEMP7
