        let numParams = 2
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: 
          nANNOTATION_PLACEHOLDER_OCCURRENCE_ROLE.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]ROLE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: tPOSITIVE_LENGTH_MEASURE.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]LINE_SPACING for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( ROLE: p0, LINE_SPACING: p1 )
